{
    "level": "A1",
    "intro": "У цій темі ти навчишся розрізняти <strong>this, that, these, those</strong> за принципом <strong>близько / далеко</strong> і <strong>однина / множина</strong>.",
    "rules": [
        {
            "label": "NEAR + SINGULAR",
            "color": "emerald",
            "text": "<strong>This</strong> — один предмет поруч:",
            "example": "This book is mine."
        },
        {
            "label": "FAR + SINGULAR",
            "color": "blue",
            "text": "<strong>That</strong> — один предмет далі від мовця:",
            "example": "That car is expensive."
        },
        {
            "label": "PLURAL",
            "color": "amber",
            "text": "<strong>These / those</strong> — форми множини: близько або далеко.",
            "example": "These shoes are new. / Those houses are old."
        }
    ]
}

{
    "title": "1. Швидка схема",
    "intro": "Поєднай відстань і число, щоб одразу вибрати правильне слово.",
    "items": [
        {
            "label": "Близько + однина",
            "title": "this",
            "subtitle": "this bag, this idea, this one"
        },
        {
            "label": "Далеко + однина",
            "title": "that",
            "subtitle": "that bag, that idea, that one"
        },
        {
            "label": "Близько + множина",
            "title": "these",
            "subtitle": "these bags, these ideas, these ones"
        },
        {
            "label": "Далеко + множина",
            "title": "those",
            "subtitle": "those bags, those ideas, those ones"
        }
    ]
}

{
    "title": "2. Основне вживання",
    "sections": [
        {
            "label": "Близько чи далеко",
            "color": "emerald",
            "description": "Демонстративи часто показують, <strong>де</strong> знаходиться предмет або ідея щодо мовця.",
            "examples": [
                {
                    "en": "This chair is comfortable.",
                    "ua": "Цей стілець зручний."
                },
                {
                    "en": "That building is very old.",
                    "ua": "Та будівля дуже стара."
                },
                {
                    "en": "Those lights look beautiful at night.",
                    "ua": "Ті вогні красиво виглядають уночі."
                }
            ]
        },
        {
            "label": "Однина і множина",
            "color": "blue",
            "description": "Форма залежить не лише від відстані, а й від того, скільки предметів ти маєш на увазі.",
            "examples": [
                {
                    "en": "This apple is sweet, but these apples are sour.",
                    "ua": "Це яблуко солодке, а ці яблука кислі."
                },
                {
                    "en": "That photo is blurry, and those photos are darker.",
                    "ua": "Та фотографія розмита, а ті фотографії темніші."
                },
                {
                    "en": "Who is that? Who are those people?",
                    "ua": "Хто це? Хто ті люди?"
                }
            ]
        },
        {
            "label": "Типові шаблони",
            "color": "amber",
            "description": "Після демонстратива часто стоїть <strong>іменник</strong>, але слово може працювати і самостійно.",
            "examples": [
                {
                    "en": "This book is easier than that one.",
                    "ua": "Ця книжка легша за ту."
                },
                {
                    "en": "These are my keys.",
                    "ua": "Це мої ключі."
                },
                {
                    "en": "I do not like those.",
                    "ua": "Мені не подобаються ті."
                }
            ],
            "note": "This / that — з одниною, these / those — з множиною."
        }
    ]
}

{
    "title": "3. Типові помилки",
    "items": [
        {
            "label": "Помилка 1",
            "color": "rose",
            "title": "This з іменником у множині.",
            "wrong": "This shoes are new.",
            "right": "✅ <span class=\"font-mono\">These shoes are new.</span>"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "That / those з неправильним дієсловом.",
            "wrong": "That are my keys.",
            "right": "✅ <span class=\"font-mono\">Those are my keys.</span> / <span class=\"font-mono\">That is my key.</span>"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Плутанина між one і ones.",
            "wrong": "I like this ones.",
            "right": "✅ <span class=\"font-mono\">I like these ones.</span> / <span class=\"font-mono\">I like this one.</span>"
        }
    ]
}

{
    "title": "4. Короткий конспект",
    "items": [
        "<strong>This</strong> — близько і один предмет.",
        "<strong>That</strong> — далі і один предмет.",
        "<strong>These</strong> — близько і кілька предметів.",
        "<strong>Those</strong> — далі і кілька предметів.",
        "Після демонстратива можна ставити іменник: <em>this book, those people</em>."
    ]
}

